mapper.select:
SELECT HOUR(upload_time) as hour,
SUM(traffic_flow) as traffic_flow
FROM tunnel_edge_compute_data
WHERE
    upload_time >= concat(#{time},' 00:00:00')
    AND upload_time <= concat(#{time},' 23:59:59')
    AND devicelist_id = #{deviceListId}

        AND traffic_flow <= #{entryTrafficLimit}

GROUP BY HOUR(upload_time)
ORDER BY Hour(upload_time);

SELECT  ROUND(avg(traffic_flow),2) trafficFlow, ROUND(avg(max_speed),2) avgSpeed  FROM t_tunnel_traffic_flow


        AND upload_time >= #{startTime}


        AND upload_time <= concat(#{endTime},' 23:59:59')

    and tunnel_id = #{tunnelId}

select DATE_FORMAT(upload_time,'%Y-%m-%d %H') hourUpload,SUM(traffic_flow) totalFlow from tunnel_edge_compute_data


        AND upload_time >= #{startTime}


        AND upload_time <= concat(#{endTime},' 23:59:59')

    and devicelist_id = #{deviceListId}

GROUP BY DATE_FORMAT(upload_time,'%Y-%m-%d %H') ORDER BY DATE_FORMAT(upload_time,'%Y-%m-%d %H') asc

select DATE_FORMAT(upload_time,'%Y-%m-%d %H') upload_hour,upload_time, CONCAT( speed1, ',', speed2, ',', speed3, ',', speed4, ',', speed5, ',', speed6, ',', speed7, ',', speed8, ',', speed9, ',', speed10, ',', speed11, ',', speed12, ',', speed13, ',', speed14, ',', speed15, ',', speed16, ',', speed17, ',', speed18, ',', speed19, ',', speed20 ) AS speed from tunnel_edge_compute_data
AND upload_time >= #{startTime}
AND upload_time <= concat(#{endTime},' 23:59:59')
and devicelist_id = #{deviceListId}
ORDER BY DATE_FORMAT(upload_time,'%Y-%m-%d %H') asc
